import { Component, EventEmitter, Output } from '@angular/core';
import { FormControl, FormGroup, Validators } from '@angular/forms';
import { RegexEmail } from '../../validation';
import { UserService } from 'src/app/services/user.service';

@Component({
  selector: 'app-change-email',
  templateUrl: './change-email.component.html',
  styleUrls: ['./change-email.component.css']
})
export class ChangeEmailComponent {
  @Output()
  statusCode = new EventEmitter<boolean>();

  @Output()
  message = new EventEmitter<string>();

  ChangePasswordForm: FormGroup = new FormGroup({
    InputPassword: new FormControl(null, [Validators.pattern(RegexPassword()), Validators.required]),
    InputNewPassword: new FormControl(null, [Validators.pattern(RegexPassword()), Validators.required]),
    InputNewPasswordRepeat: new FormControl(null, [Validators.pattern(RegexPassword()), Validators.required])
  };

  constructor(private userService: UserService) { }

  password: string = "";
  newPassword: string = "";
  newPasswordRepeat: string = "";

  onSubmit(): void {
    this.userService.UpdatePassword(this.password, this.newPassword, this.newPasswordRepeat).subscribe(status => {
      this.statusCode.emit(status.statusCode);
      this.message.emit(status.message);
    });
  }
}
<div class="d-flex justify-content-center">
    <fieldset class="w-100 border border-white rounded shadow">
        <form [formGroup]="ChangeEmailForm" class="p-3" (ngSubmit)="onSubmit()">

            <div class="input-group mt-2">
                <label class="input-group-addon me-2" for="InputPassword"><img src="/assets/images/password.png"
                        class="icon" /></label>
                <input formControlName="InputPassword" type="password"
                    class="form-control form-control-sm shadow rounded"
                    [ngClass]="ChangePasswordForm.get('InputPassword')?.touched ? (ChangePasswordForm.get('InputPassword')?.valid ? 'is-valid' : 'is-invalid') : ''"
                    [(ngModel)]='password' id="InputPassword" placeholder="Old Password">
            </div>
            <div class="input-group mt-2">
                <label class="input-group-addon me-2" for="InputNewPassword"><img
                        src="/assets/images/password_repeat.png" class="icon" /></label>
                <input formControlName="InputNewPassword" type="password"
                    class="form-control form-control-sm shadow rounded"
                    [ngClass]="ChangePasswordForm.get('InputNewPassword')?.touched ? (ChangePasswordForm.get('InputNewPassword')?.valid ? 'is-valid' : 'is-invalid') : ''"
                    [(ngModel)]='newPassword' id="InputNewPassword" placeholder="New Password">
            </div>

            <button [disabled]="ChangeEmailForm.invalid" type="submit" class="btn btn-light text-dark w-100 mt-3 shadow">Change Password</button>
        </form>
    </fieldset>
</div>
